import{_ as e,o as l,c as a,a2 as d}from"./chunks/framework.Pywvta2k.js";const y=JSON.parse('{"title":"实战案例：女性阴虚湿热型辨证全案","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/08-实战案例/02-普明辨证案例.md","filePath":"tcm-data/08-实战案例/02-普明辨证案例.md","lastUpdated":1781084559000}'),i={name:"tcm-data/08-实战案例/02-普明辨证案例.md"};function r(n,t,s,g,h,x){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="实战案例-女性阴虚湿热型辨证全案" tabindex="-1">实战案例：女性阴虚湿热型辨证全案 <a class="header-anchor" href="#实战案例-女性阴虚湿热型辨证全案" aria-label="Permalink to &quot;实战案例：女性阴虚湿热型辨证全案&quot;">​</a></h1><blockquote><p>案例编号：CASE-TEMPLATE-F-001 辨证依据：黄元御《四圣心源》+ 傅青主《女科》 本案例为阴虚湿热型的标准辨证模板</p></blockquote><hr><h2 id="一、患者信息" tabindex="-1">一、患者信息 <a class="header-anchor" href="#一、患者信息" aria-label="Permalink to &quot;一、患者信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;">性别</td><td style="text-align:left;">女</td></tr><tr><td style="text-align:left;">年龄</td><td style="text-align:left;">35-45岁区间</td></tr><tr><td style="text-align:left;">体型</td><td style="text-align:left;">偏瘦/中等</td></tr><tr><td style="text-align:left;">体质倾向</td><td style="text-align:left;">阴虚湿热型</td></tr></tbody></table><blockquote><p><strong>说明</strong>：本案例为典型阴虚夹湿体质辨证模板，具体四诊资料见正文。</p></blockquote><hr><h2 id="二、症状汇总-按系统" tabindex="-1">二、症状汇总（按系统） <a class="header-anchor" href="#二、症状汇总-按系统" aria-label="Permalink to &quot;二、症状汇总（按系统）&quot;">​</a></h2><h3 id="上焦-心肺" tabindex="-1">上焦（心肺） <a class="header-anchor" href="#上焦-心肺" aria-label="Permalink to &quot;上焦（心肺）&quot;">​</a></h3><ul><li>面色萎黄、两颧微红</li><li>口唇干燥、易生疮</li><li>咽喉不适、偶有干咳</li><li>心烦易怒、睡眠浅</li><li>偶尔盗汗</li></ul><h3 id="中焦-脾胃" tabindex="-1">中焦（脾胃） <a class="header-anchor" href="#中焦-脾胃" aria-label="Permalink to &quot;中焦（脾胃）&quot;">​</a></h3><ul><li>胃脘胀满、饭后为甚</li><li>偶有反酸烧心</li><li>大便先干后溏、排便不畅</li><li>口干不欲多饮</li></ul><h3 id="下焦-肝肾" tabindex="-1">下焦（肝肾） <a class="header-anchor" href="#下焦-肝肾" aria-label="Permalink to &quot;下焦（肝肾）&quot;">​</a></h3><ul><li>月经量偏少、色暗有块</li><li>经前乳房胀痛、烦躁</li><li>腰膝酸软</li><li>带下色黄、质黏</li><li>小便偏黄</li></ul><hr><h2 id="三、病机分析" tabindex="-1">三、病机分析 <a class="header-anchor" href="#三、病机分析" aria-label="Permalink to &quot;三、病机分析&quot;">​</a></h2><p><strong>阴虚为本、湿热为标 → 上燥下湿 → 虚实夹杂</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">层次</th><th style="text-align:left;">病机</th><th style="text-align:left;">症状证据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>本</strong></td><td style="text-align:left;">肝肾阴虚</td><td style="text-align:left;">面色萎黄、月经量少、腰膝酸软</td></tr><tr><td style="text-align:left;"><strong>标</strong></td><td style="text-align:left;">湿热蕴结</td><td style="text-align:left;">带下黄黏、面部生疮、反酸</td></tr><tr><td style="text-align:left;"><strong>变</strong></td><td style="text-align:left;">气机不畅</td><td style="text-align:left;">脘腹胀满、经前乳胀</td></tr></tbody></table><p><strong>核心辨证要点</strong>：</p><ul><li>阴虚夹湿最难调治：养阴则助湿，化湿则伤阴</li><li>贵在&quot;运枢机&quot;——斡旋中焦气机，使水火既济</li><li>当以辛开苦降为法，不可一味滋补</li></ul><hr><h2 id="四、主方-加减甘露饮-养阴化湿方" tabindex="-1">四、主方：加减甘露饮（养阴化湿方） <a class="header-anchor" href="#四、主方-加减甘露饮-养阴化湿方" aria-label="Permalink to &quot;四、主方：加减甘露饮（养阴化湿方）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">药物</th><th style="text-align:center;">剂量</th><th style="text-align:left;">功能</th></tr></thead><tbody><tr><td style="text-align:left;">生地黄</td><td style="text-align:center;">15g</td><td style="text-align:left;">养阴清热</td></tr><tr><td style="text-align:left;">麦冬</td><td style="text-align:center;">12g</td><td style="text-align:left;">润肺生津</td></tr><tr><td style="text-align:left;">石斛</td><td style="text-align:center;">10g</td><td style="text-align:left;">养胃阴</td></tr><tr><td style="text-align:left;">黄芩</td><td style="text-align:center;">6g</td><td style="text-align:left;">清热燥湿</td></tr><tr><td style="text-align:left;">茵陈</td><td style="text-align:center;">9g</td><td style="text-align:left;">利湿清热</td></tr><tr><td style="text-align:left;">枳壳</td><td style="text-align:center;">6g</td><td style="text-align:left;">行气宽中</td></tr><tr><td style="text-align:left;">枇杷叶</td><td style="text-align:center;">9g</td><td style="text-align:left;">降逆和胃</td></tr><tr><td style="text-align:left;">茯苓</td><td style="text-align:center;">12g</td><td style="text-align:left;">淡渗利湿</td></tr><tr><td style="text-align:left;">泽泻</td><td style="text-align:center;">6g</td><td style="text-align:left;">利湿不伤阴</td></tr><tr><td style="text-align:left;">白芍</td><td style="text-align:center;">10g</td><td style="text-align:left;">柔肝养血</td></tr><tr><td style="text-align:left;">甘草</td><td style="text-align:center;">5g</td><td style="text-align:left;">调中和药</td></tr></tbody></table><h3 id="煎服法" tabindex="-1">煎服法 <a class="header-anchor" href="#煎服法" aria-label="Permalink to &quot;煎服法&quot;">​</a></h3><p>诸药同煎30分钟 → 二煎20分钟 → 合并分早晚温服</p><h3 id="调护要点" tabindex="-1">调护要点 <a class="header-anchor" href="#调护要点" aria-label="Permalink to &quot;调护要点&quot;">​</a></h3><ul><li>忌辛辣刺激、过甜油腻</li><li>宜清淡饮食、适当饮水</li><li>不宜过度运动出汗</li><li>保持情绪舒畅</li></ul><h3 id="疗程" tabindex="-1">疗程 <a class="header-anchor" href="#疗程" aria-label="Permalink to &quot;疗程&quot;">​</a></h3><p>先服5剂，观舌苔变化后再调</p><hr><h2 id="五、预后判断" tabindex="-1">五、预后判断 <a class="header-anchor" href="#五、预后判断" aria-label="Permalink to &quot;五、预后判断&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">阶段</th><th style="text-align:left;">预期变化</th></tr></thead><tbody><tr><td style="text-align:left;">1-2周</td><td style="text-align:left;">湿热渐去：苔转薄、带下减、口疮愈</td></tr><tr><td style="text-align:left;">2-4周</td><td style="text-align:left;">阴液渐复：口干减、睡眠改善</td></tr><tr><td style="text-align:left;">1-3月</td><td style="text-align:left;">气血渐调：面色转润、月经趋于规律</td></tr><tr><td style="text-align:left;">3-6月</td><td style="text-align:left;">体质转变：阴虚湿热体质整体改善</td></tr></tbody></table><hr><h2 id="六、加减法-随证化裁" tabindex="-1">六、加减法（随证化裁） <a class="header-anchor" href="#六、加减法-随证化裁" aria-label="Permalink to &quot;六、加减法（随证化裁）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">兼证</th><th style="text-align:left;">加减</th></tr></thead><tbody><tr><td style="text-align:left;">月经不调</td><td style="text-align:left;">加当归10g、川芎6g</td></tr><tr><td style="text-align:left;">失眠重</td><td style="text-align:left;">加酸枣仁15g、夜交藤15g</td></tr><tr><td style="text-align:left;">胃胀甚</td><td style="text-align:left;">加陈皮6g、砂仁6g（后下）</td></tr><tr><td style="text-align:left;">带下多</td><td style="text-align:left;">加椿皮9g、芡实12g</td></tr><tr><td style="text-align:left;">腰酸痛</td><td style="text-align:left;">加杜仲12g、续断9g</td></tr><tr><td style="text-align:left;">便秘</td><td style="text-align:left;">加火麻仁15g、瓜蒌仁10g</td></tr></tbody></table><hr><p><em>本案例为阴虚湿热型基本辨证模板。实际临床需结合舌脉，随证治之。</em></p>',37)])])}const f=e(i,[["render",r]]);export{y as __pageData,f as default};
